INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('islands-d0d1b9a2-moex-00018', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司銷售電器用品並提供2年期的保固服務，保固合約不單獨銷售。該公司於X5年以現金銷 售800台電器用品（每台單價$25,000），並估計每台保固成本為$1,000。實際於X5年支付零件 費$80,000與人工費$35,000。甲公司於銷售時預估並認列保固負債及保固費用。但會計人員誤以 現金基礎記帳，僅在實際支付時認列費用。試問此錯誤將如何影響甲公司X5年之財報比率？', '["流動比率高估、利潤率高估", "流動比率低估、利潤率高估", "流動比率高估、利潤率低估", "流動比率低估、利潤率低估"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00019', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年成立時以每股$25，發行面額$10的普通股30,000股。該公司於X2年5月13日首 次以每股$28購回庫藏股5,000股，並於X2年6月24日及7月1日分別以每股$32及$24的價 格各出售2,000股，X2年9月3日又註銷剩餘1,000股。請問X2年4項庫藏股交易如何影響股 東權益的總金額？', '["減少$3,000", "減少$8,000", "減少$28,000", "減少$143,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00020', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '有關債券投資之敘述，下列何者正確？', '["若債券是折價投資，隨著時間經過，各期攤銷之折價數額會越來越少", "若債券是溢價投資，隨著時間經過，各期認列之利息收入會越來越高", "不論債券是折價或溢價投資，隨著時間經過，各期攤銷之折溢價數額均會越來越高", "不論債券是折價或溢價投資，隨著時間經過，各期認列之利息收入均會越來越低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00021', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司X8年度之稅後淨利為$500,000，當年度並有下列事項：', '["應付公司債溢價攤銷$10,000", "遞延所得稅資產減少$6,000", "透過其他綜合損益按公允價值衡量投資（流動資產），投資金額增加$15,000", "待出售非流動資產之處分利益$8,000 請問甲公司X8年度營業活動之現金流量為何？"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00022', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初對其40位經理人員施行一項認股權計畫，若於X3年底尚在職者，則每人得以 $100認購公司股票，每人之認購股數依公司X3年底之市占率成長幅度而定，每成長5%之認購 股數為1,000，若成長10%認購股數則為2,000，以此類推。相關資料如下： 估計每個認股權公 當年度實際離職 估計X3年底前尚會 估計 X3 年底之市 日期 允價值 人數 離職人數 占率成長幅度 X1年初 $20 10% X1年底 $25 5 5 5% X2年底 $22 8 4 10% 有關甲公司此項認股權計畫，下列敘述何者正確？', '["X1年度應認列之酬勞成本為$250,000", "X2年度應認列之酬勞成本為$413,333", "X1年底相關之資本公積為$400,000", "X2年底相關之資本公積為$674,666"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00023', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'essay', '基於預算是估列數，而從籌編到立法院審議歷時甚久，因此實際執行時
往往有不敷支應之問題，為此「預算法」及「各機關單位預算執行要點」
規範了各種預算執行彈性，包括流用、第一預備金、第二預備金、追加
預算及特別預算。請就其中流用的規定闡述之，含：
經常門與資本門間互相流用的限制為何？（10分）
請列出以下不可以流用的號碼：①機關別 ②政事別 ③用途別
④業務科目 ⑤計畫科目（5分）
就前項列出可以流用的號碼及流用百分比？（5 分）
在可以流用的號碼中，該號碼下一級分類不能流用之經費為何者？（5分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00024', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'essay', '防汛期間，颱風侵襲次數頻繁，如果在首次颱風侵襲時，依預算法第83條
規定編列災害復原重建特別預算500 億元，並一次編足多年期預算，而
後又有同性質第二個颱風特別預算350億元要編列，則在原有500億元基
礎上追加350億元，或另外獨立編列 350 億元二種提議，以下表所列格
式說明之。（25分）
事項 追加方式 獨立編列方式
編列方式是否可行
第二個颱風是否一定一次編足
二個颱風決算編造次數', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00025', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '下列非屬政府公務機關於年度單位預算中，以歲出資本門納編者，計有幾項？①償還公債本金', '["修建橋樑延壽", "作業基金以公積撥充基金", "補助下級地方政府購買土地  ⑤支付賒借債 務利息  ⑥投資民營企業", "2項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00026', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '立法院依憲法第63條規定有審議預算案之權，立法委員於審議中央政府總預算案時，應受憲法 第70條規定，立法院對於行政院所提預算案，不得為增加支出之提議。試問下列何者非屬立法 院增加支出之提議？', '["決議請行政院加發半個月公教人員年終工作獎金", "決議將款項目節間移動增加原預算之項目", "決議將農業部預算調整移動至經濟部", "決議將款項目節之原預算削減"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00027', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-ddeb88e9', 'sub-islands-d0d1b9a2-02', NULL, 'single_choice', '下列屬中央政府管理之信託基金，計有幾項？①學產基金  ②外籍配偶照顧輔導基金  ③農民退', '["在校學生獎學基金  ⑤保險業務發展基金  ⑥中央公教人員急難救助基金", "2項", "3項", "4項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "c868bde2a41c", "answer_pdf_sha1": "9585cbcdc6c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL)
